using Unity.VisualScripting.Antlr3.Runtime.Misc; using UnityEngine; public class Enemy_Health : Entity_Health {        [Header("On Damage Knockback")]     [SerializeField] private Vector2 onDamageKnockback = new Vector2(1f, 2.5f);      [Header("On Heavy KnockBack")]     [SerializeField] private float heavyKnockThreshold = .3f;     [SerializeField] private Vector2 onHeavyDamageKnockBack = new Vector2(5f, 5f);      [Header("Music")]     [SerializeField] private AudioClip damagedClip;     public  AudioSource enemyAudio;     private Enemy enemy => GetComponent<Enemy>();         public override bool TakeDamage(float damage, float elementalDamage, ElementType element, Transform DamageDealer)     {         if (IsDead) return false;          PlayHitEffects();          Vector2 knockback = CalculateKnockback(damage, DamageDealer);         entity?.ReceiveKnockback(knockback, knockbackDuration);         if (DamageDealer.CompareTag("Player"))         {             enemy.TryEnterAttackState(DamageDealer);         }        bool wasHit= base.TakeDamage(damage, elementalDamage, element, DamageDealer);         if (wasHit == false) return false;          if (enemyAudio != null&&damagedClip!=null)         {             enemyAudio.PlayOneShot(damagedClip,0.4f);         }         return true;     }     protected override Vector2 CalculateKnockback(float damage, Transform damageDealer)     {         float healthPercentageTaken = damage / entityStats.GetMaxHealth();         bool isHeavyDamage = healthPercentageTaken > heavyKnockThreshold;         Vector2 knockback = isHeavyDamage ? onHeavyDamageKnockBack : onDamageKnockback;          int direction = transform.position.x > damageDealer.position.x ? 1 : -1;         knockback.x = knockback.x * direction;          return knockback;     }  } 